check_review_smell_protocol_reference() {
  local root="$1"
  local label="$2"
  local protocol="$root/references/ddd-review-smell-protocol.md"

  grep -q "The coordinator owns breadth" "$protocol" || fail "$label smell protocol should assign breadth to coordinator"
  grep -q "Investigators own depth" "$protocol" || fail "$label smell protocol should assign depth to investigators"
  grep -q "Coordinator breadth scan" "$protocol" || fail "$label smell protocol should define coordinator breadth scan"
  grep -q "Depth investigation tags" "$protocol" || fail "$label smell protocol should define depth classification tags"
  grep -q "Depth investigators start from one coarse smell family and then search for sibling shapes in the same family" "$protocol" || fail "$label smell protocol should require sibling-shape expansion in depth"
  grep -q "Codex and Claude Code review runtimes are expected to have subagent/task capability" "$protocol" || fail "$label smell protocol should assume Codex/Claude Code subagent capability"
  grep -q "Dispatch depth investigators for coarse smell families before coordinator depth analysis" "$protocol" || fail "$label smell protocol should require subagent dispatch"
  grep -q "treat that as an environment defect and name it in the final Depth execution line" "$protocol" || fail "$label smell protocol should expose missing subagent as environment defect"
  grep -q "No-finding is positive-shape proof" "$protocol" || fail "$label smell protocol should define positive-shape no-finding"
  grep -q "Do not clear an axis because negative examples were not found" "$protocol" || fail "$label smell protocol should reject absence-based no-finding"
  grep -q "Final report shape" "$protocol" || fail "$label smell protocol should define final report shape"
  grep -q "The final answer reports judgments, not the full working evidence" "$protocol" || fail "$label smell protocol should keep final output judgment-oriented"
  grep -q "Coordinator merge contract" "$protocol" || fail "$label smell protocol should define coordinator merge contract"
  grep -q "Every returned family verdict must be represented exactly once in the final judgment path" "$protocol" || fail "$label smell protocol should keep returned family verdicts visible"
  grep -q "Use selected working evidence for verdicts that support no-finding, partial coverage, evidence gap, or return but are not themselves Findings" "$protocol" || fail "$label smell protocol should require selected evidence for non-finding verdicts"
  grep -q "A broader finding cannot absorb recovery wiring, collaboration mechanism, candidate-owner, state vocabulary, or CQRS inventory verdicts" "$protocol" || fail "$label smell protocol should not hide linked verdicts behind broad findings"
  grep -q "Fixed review axes are tags" "$protocol" || fail "$label smell protocol should treat axes as tags"
  grep -q "Correct Shape Whitelist" "$protocol" || fail "$label smell protocol should define correct-shape whitelist"
  grep -q "does not try to enumerate every possible bad smell" "$protocol" || fail "$label smell protocol should avoid smell enumeration"
  grep -q "Any touched shape that does not map to a whitelist row becomes a smell" "$protocol" || fail "$label smell protocol should derive smells from whitelist deviations"
  grep -q "Aggregate lifecycle: one Aggregate Root owns one lifecycle and invariant boundary" "$protocol" || fail "$label smell protocol should whitelist aggregate lifecycle shape"
  grep -q "Repository/API: one Repository saves one Aggregate Root plus owned children/value objects" "$protocol" || fail "$label smell protocol should whitelist repository shape"
  grep -q "CQRS: write repositories serve command-side aggregate facts" "$protocol" || fail "$label smell protocol should whitelist CQRS shape"
  grep -q "coarse_family | whitelist_row | trigger_evidence | depth_scope | sibling_scope | positive_shape_evidence | verdict | judgment" "$protocol" || fail "$label smell protocol should define coarse-family work packets"
  grep -q "Allowed \`verdict\`: \`violation\`, \`return-to-domain-modeling\`, \`return-to-design\`, \`evidence-gap\`, \`positive-shape-no-finding\`, \`spawned-family\`" "$protocol" || fail "$label smell protocol should constrain family verdicts"
  grep -q "The coordinator may use risk-router cards to classify a deviation, but it must not convert a card name into a finding before investigation" "$protocol" || fail "$label smell protocol should not turn cards into findings before investigation"
  grep -q "An investigator must not run a full global review" "$protocol" || fail "$label smell protocol should prevent global subagent review"
  grep -q "A spawned family is appended to the same queue" "$protocol" || fail "$label smell protocol should close spawned smell families"
  grep -q "Findings can only be generated from negative or gap depth decisions" "$protocol" || fail "$label smell protocol should generate findings from depth decisions"
  grep -q "Do not wait indefinitely" "$protocol" || fail "$label smell protocol should preserve liveness"
  grep -q "Depth notes may not collapse multiple repository methods, collaboration flows, terminal facts, parent states, commands, or CQRS methods when those siblings drive different judgments" "$protocol" || fail "$label smell protocol should reject over-grouped depth proof"
  grep -q "If a depth investigator cannot prove positive CQRS shape, decision is evidence gap, not no branch finding" "$protocol" || fail "$label smell protocol should reject CQRS no-finding without positive shape"
  grep -q "Stale-command depth enumerates each later command after durable fact: cancel, retry/start, new payment, reopen, execution, and closure" "$protocol" || fail "$label smell protocol should enumerate stale commands"
  grep -q "Collaboration depth enumerates delivery, refund, dispute, settlement, split closure, and payment recovery mechanisms independently" "$protocol" || fail "$label smell protocol should enumerate collaboration mechanisms"
  grep -q "Recovery-wiring depth distinguishes a recovery command or handler existing in code from that command being reachable in production" "$protocol" || fail "$label smell protocol should distinguish recovery existence from production wiring"
  grep -q "Repository candidate-owner depth emits one terse row per semantic method whenever multiple aggregate or lifecycle-owner candidates are saved or coordinated" "$protocol" || fail "$label smell protocol should require visible repository candidate-owner rows"
  grep -q "CQRS depth emits visible method-level inventory for read-shaped write-side methods and shared adapters before any product-read no-finding" "$protocol" || fail "$label smell protocol should require visible CQRS inventory before no-finding"
  grep -q "payment_pending must be classified as an open/stale parent state when durable child or payment facts can outrank it" "$protocol" || fail "$label smell protocol should include pending parent-state risk"
  grep -q "Split refund/settlement terminal rows must decide whether terminal agreement facts or events occur before both execution facts and aggregate closure complete" "$protocol" || fail "$label smell protocol should require split terminal ordering rows"
  grep -q "Repository/API depth rows must be one row per semantic method" "$protocol" || fail "$label smell protocol should require per-method repository rows"
  grep -q "Collaboration depth rows must be one row per lifecycle flow" "$protocol" || fail "$label smell protocol should require per-flow collaboration rows"
  grep -q "Do not emit a positive coverage table in complex lifecycle/repository/event/CQRS reviews" "$protocol" || fail "$label smell protocol should forbid positive coverage tables"
  grep -q "Positive clearance phrases such as no issue, no similar issue, no branch finding, inventory-only, 未发现, or 适配正确 are valid only when the same decision names positive correct-shape evidence" "$protocol" || fail "$label smell protocol should require positive shape for clearance"
  grep -q "Triggered families with incomplete depth proof become evidence gap or return, never positive coverage" "$protocol" || fail "$label smell protocol should downgrade incomplete proof"
}

check_review_smell_protocol_reference "$CLAUDE_ROOT" "Claude"
check_review_smell_protocol_reference "$CODEX_ROOT" "Codex"
